380→    @Override
381→    public Loader<List<Recipient>> onCreateLoader(int id, Bundle args) {
382→        switch (id) {
383→            case LOADER_ID_FILTERING: {
384→                String query = args != null && args.containsKey(ARG_QUERY) ? args.getString(ARG_QUERY) : "";
385→                adapter.setHighlight(query);
386→                return new RecipientLoader(getContext(), cryptoProvider, query);
387→            }
388→            case LOADER_ID_ALTERNATES: {
389→                Uri contactLookupUri = alternatesPopupRecipient.getContactLookupUri();
390→                if (contactLookupUri != null) {
391→                    return new RecipientLoader(getContext(), cryptoProvider, contactLookupUri, true);
392→                } else {
393→                    return new RecipientLoader(getContext(), cryptoProvider, alternatesPopupRecipient.address);
394→                }
395→            }
396→        }
397→
398→        throw new IllegalStateException("Unknown Loader ID: " + id);
399→    }
