428→    public boolean tryPerformCompletion() {
429→        if (!hasUncompletedText()) {
430→            return false;
431→        }
432→        int previousNumRecipients = getTokenCount();
433→        performCompletion();
434→        int numRecipients = getTokenCount();
435→
436→        return previousNumRecipients != numRecipients;
437→    }
