448→    static private boolean isPlaceholderText(String currentCompletionText) {
449→        // TODO string matching here is sort of a hack, but it's somewhat reliable and the info isn't easily available
450→        return currentCompletionText.startsWith("+") && currentCompletionText.substring(1).matches("[0-9]+");
451→    }
