459→    @Override
460→    public void onRecipientChange(Recipient recipientToReplace, Recipient alternateAddress) {
461→        alternatesPopup.dismiss();
462→
463→        List<Recipient> currentRecipients = getObjects();
464→        int indexOfRecipient = currentRecipients.indexOf(recipientToReplace);
465→        if (indexOfRecipient == -1) {
466→            Timber.e("Tried to refresh invalid view token!");
467→            return;
468→        }
469→        Recipient currentRecipient = currentRecipients.get(indexOfRecipient);
470→
471→        currentRecipient.address = alternateAddress.address;
472→        currentRecipient.addressLabel = alternateAddress.addressLabel;
473→        currentRecipient.cryptoStatus = alternateAddress.cryptoStatus;
474→
475→        View recipientTokenView = getTokenViewForRecipient(currentRecipient);
476→        if (recipientTokenView == null) {
477→            Timber.e("Tried to refresh invalid view token!");
478→            return;
479→        }
480→
481→        bindObjectView(currentRecipient, recipientTokenView);
482→
483→        if (listener != null) {
484→            listener.onTokenChanged(currentRecipient);
485→        }
486→
487→        invalidate();
488→        redrawTokens();
489→        invalidateCursorPositionHack();
490→    }
