531→    /**
532→     * Find the token view tied to a given recipient. This method relies on spans to
533→     * be of the RecipientTokenSpan class, as created by the buildSpanForObject method.
534→     */
535→    private View getTokenViewForRecipient(Recipient currentRecipient) {
536→        Editable text = getText();
537→        if (text == null) {
538→            return null;
539→        }
540→
541→        RecipientTokenSpan[] recipientSpans = text.getSpans(0, text.length(), RecipientTokenSpan.class);
542→        for (RecipientTokenSpan recipientSpan : recipientSpans) {
543→            if (recipientSpan.getToken().equals(currentRecipient)) {
544→                return recipientSpan.view;
545→            }
546→        }
547→
548→        return null;
549→    }
