import com.fsck.k9.view.UserInputEmailAddressParser
import com.fsck.k9.view.InvalidEmailAddressException

fun main() {
    val parser = UserInputEmailAddressParser()

    // Test the specific issue mentioned in the bug report
    try {
        val result = parser.parse("xxx@gmail.com/")
        println("ERROR: Should have thrown InvalidEmailAddressException for xxx@gmail.com/")
    } catch (e: InvalidEmailAddressException) {
        println("✅ Correctly rejected xxx@gmail.com/ - ${e.message}")
    }

    // Test valid email
    try {
        val result = parser.parse("test@gmail.com")
        println("✅ Correctly accepted test@gmail.com - ${result[0].address}")
    } catch (e: Exception) {
        println("ERROR: Should have accepted test@gmail.com - ${e.message}")
    }

    // Test trailing space (should still work)
    try {
        val result = parser.parse("test@gmail.com ")
        println("✅ Correctly accepted test@gmail.com with trailing space - ${result[0].address}")
    } catch (e: Exception) {
        println("ERROR: Should have accepted test@gmail.com with trailing space - ${e.message}")
    }
}"}

