            }
    }

    private fun Address.isIncomplete() = hostname.isNullOrBlank()

    private fun Address.isNonAsciiAddress() = !CharsetUtil.isASCII(address)

    /**
     * Validates if an email address conforms to RFC 5321 specification.
     * This includes checking for invalid characters and format issues.
     */
    private fun Address.isValidRfc5321Address(): Boolean {
        val emailAddress = this.address ?: return false

        // Check for basic format: must contain exactly one @ symbol
        val atCount = emailAddress.count { it == '@' }
        if (atCount != 1) return false

        val parts = emailAddress.split('@')
        if (parts.size != 2) return false

        val localPart = parts[0]
        val domainPart = parts[1]

        // Both parts must not be empty
        if (localPart.isEmpty() || domainPart.isEmpty()) return false

        // Check for invalid trailing characters (like the reported '/' issue)
        if (emailAddress.endsWith("/") || emailAddress.endsWith("\\") || 
            emailAddress.endsWith(" ") || emailAddress.endsWith("\t") ||
            emailAddress.endsWith("\n") || emailAddress.endsWith("\r")) {
            return false
        }

        // Validate local part (before @)
        if (!isValidLocalPart(localPart)) return false

        // Validate domain part (after @)
        if (!isValidDomainPart(domainPart)) return false

        return true
    }

    /**
     * Validates the local part of an email address (before the @)
     */
    private fun isValidLocalPart(localPart: String): Boolean {
        if (localPart.isEmpty() || localPart.length > 64) return false

        // Cannot start or end with a dot
        if (localPart.startsWith(".") || localPart.endsWith(".")) return false

        // Cannot have consecutive dots
        if (localPart.contains("..")) return false

        // Check for valid characters in local part
        // RFC 5321 allows: A-Z a-z 0-9 ! # $ % & ' * + - / = ? ^ _ ` { | } ~ and .
        val validLocalChars = "ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789!#\$%&'*+-/=?^_`{|}~."
        return localPart.all { it in validLocalChars }
    }

    /**
     * Validates the domain part of an email address (after the @)
     */
    private fun isValidDomainPart(domainPart: String): Boolean {
        if (domainPart.isEmpty() || domainPart.length > 253) return false

        // Cannot start or end with a hyphen or dot
        if (domainPart.startsWith("-") || domainPart.endsWith("-") ||
            domainPart.startsWith(".") || domainPart.endsWith(".")) return false

        // Split by dots to check each label
        val labels = domainPart.split(".")
        if (labels.isEmpty()) return false

        // Each label must be valid
        return labels.all { label ->
            isValidDomainLabel(label)
        }
    }

    /**
     * Validates a single label in the domain part
     */
    private fun isValidDomainLabel(label: String): Boolean {
        if (label.isEmpty() || label.length > 63) return false

        // Cannot start or end with hyphen
        if (label.startsWith("-") || label.endsWith("-")) return false

        // Must contain only letters, digits, and hyphens
        return label.all { it.isLetterOrDigit() || it == '-' }
    }
